import jwt from "jsonwebtoken";
var createToken = (payload, secret, expaired) => {
  const token = jwt.sign(payload, secret, { expiresIn: expaired });
  return token;
};
var verifyToken = (token, secret) => {
  const secretData = secret === "access" ? config_index_default.jwt_access_secret : config_index_default.jwt_refresh_secret;
  try {
    const validToken = jwt.verify(token, secretData);
    return { success: true, validToken };
  } catch (error) {
    return { success: false, error: error.message };
  }
};
