// src/modules/auth/auth.service.ts
import bcrypt from "bcrypt";
var registerUser = async (payload) => {
  const { email, password, role } = payload;
  if (role !== "TENANT" && role !== "LANDLORD") {
    throw new Error("The role field must be either TENANT or LANDLORD.");
  }
  const isExistUser = await prisma_default.user.findUnique({
    where: { email }
  });
  if (isExistUser) {
    throw new Error("User already exsist using this email");
  }
  const hashPass = await bcrypt.hash(password, Number(config_index_default.bcrypt_salt_rounds));
  const createUser = await prisma_default.user.create({
    data: {
      ...payload,
      password: hashPass
    },
    omit: {
      password: true
    }
  });
  return createUser;
};
var loginUser = async (payload) => {
  const { email, password } = payload;
  const user = await prisma_default.user.findUnique({
    where: { email }
  });
  if (!user) {
    throw new Error("User not found! Please provide valid email");
  }
  ;
  const isPassHash = await bcrypt.compare(password, user.password);
  if (!isPassHash) {
    throw new Error("Invalid Credentials");
  }
  ;
  const payloadJwt = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtToken.createToken(payloadJwt, config_index_default.jwt_access_secret, config_index_default.token_access_expaired);
  const refreshToken = jwtToken.createToken(payloadJwt, config_index_default.jwt_refresh_secret, config_index_default.token_refresh_expaired);
  return { accessToken, refreshToken };
};
var getProfile = async (id) => {
  const user = await prisma_default.user.findUnique({
    where: { id },
    omit: { password: true }
  });
  return user;
};
var authService = {
  registerUser,
  loginUser,
  getProfile
};

