// src/middlewares/authRole.ts
import status2 from "http-status";
var authRole = (...requiredRole) => {
  return catchAsyncFunc(async (req, res, next) => {
    const token = req.cookies.accessToken ? req.cookies.accessToken : req.headers.authorization?.startsWith("Besre ") ? req.headers.authorization?.split(" ")[1] : req.headers.authorization;
    if (!token) {
      throw new Error("You're not login. Please login to access this resourc");
    }
    ;
    const validToken = jwtToken.verifyToken(token, "access");
    if (validToken.success === false) {
      throw new Error(validToken.error);
    }
    ;
    const { id, role } = validToken.validToken;
    console.log(role);
    if (!requiredRole.includes(role)) {
      res.status(status2.FORBIDDEN).json({
        success: false,
        statusCode: status2.FORBIDDEN,
        message: "Forbidden, You don't have permission to access this resoruse."
      });
    }
    ;
    const user = await prisma_default.user.findUnique({
      where: { id }
    });
    if (!user) {
      throw new Error("User Not Found. Please login again ");
    }
    if (user.status === "BANNED") {
      throw new Error("You're account is blocked. Please contact to support");
    }
    ;
    req.presentUser = {
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role
    };
    next();
  });
};
var authRole_default = authRole;

